const ABBREV_MAP = {'professional scrum master':'PSM','professional scrum master advanced':'PSM-A','professional scrum master ai essentials':'PSM-AI','professional scrum master - ai essentials':'PSM-AI','professional scrum product owner':'PSPO','professional scrum product owner advanced':'A-PSPO','professional scrum product owner - advanced':'A-PSPO','professional scrum product owner ai essentials':'PSPO-AI','professional scrum product owner - ai essentials':'PSPO-AI','applying professional scrum':'APS','professional scrum with kanban':'PSK','professional scrum facilitation skills':'PSFS','scaled professional scrum':'SPS','professional agile leadership essentials':'PAL-E','professional agile leadership - essentials':'PAL-E','professional agile leadership evidence-based management':'PAL-EBM','professional agile leadership - evidence-based management':'PAL-EBM','professional agile leadership - evidence based management':'PAL-EBM','professional scrum with user experience':'PSU'};
