  for (const [name,abbrev] of Object.entries(ABBREV_MAP)) {
    if (lower===name&&name.length>bestMatch.length) { bestMatch=name; bestAbbrev=abbrev; }
  }
  if (bestAbbrev) return bestAbbrev;
  for (const [name,abbrev] of Object.entries(ABBREV_MAP)) {
